import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Pie, Line } from 'react-chartjs-2';
import 'chart.js/auto';
import './dashboard.css';
import Header from './Header';

const API_URL = 'http://localhost:9000';

const Dashboard = ({ token }) => {
    const [portfolio, setPortfolio] = useState([]);
    const [marketData, setMarketData] = useState([]);
    const [buySymbol, setBuySymbol] = useState('');
    const [buyQuantity, setBuyQuantity] = useState('');
    const [error, setError] = useState('');
    const [username, setUsername] = useState('');

    useEffect(() => {
        if (!token) {
            setError("Utilisateur non connecté");
            return;
        }
        const decodedToken = JSON.parse(atob(token.split('.')[1]));
        setUsername(decodedToken.username);
        fetchPortfolio(decodedToken.username);
        fetchMarketData();
    }, [token]);

    const fetchPortfolio = async (user) => {
        try {
            const response = await axios.get(`${API_URL}/portfolio/${user}`);
            setPortfolio(response.data);
        } catch (error) {
            setError("Erreur lors du chargement du portefeuille.");
        }
    };

    const fetchMarketData = async () => {
        try {
            const response = await axios.get(`${API_URL}/market-data`);
            setMarketData(response.data);
        } catch (error) {
            setError("Erreur lors du chargement des données du marché.");
        }
    };

    const handleAddAsset = async (e) => {
        e.preventDefault();
        if (!buySymbol || !buyQuantity) {
            setError("Veuillez remplir tous les champs.");
            return;
        }
        try {
            await axios.post(`${API_URL}/portfolio/add`, { userId: username, symbol: buySymbol, quantity: parseInt(buyQuantity) });
            setBuySymbol('');
            setBuyQuantity('');
            fetchPortfolio(username);
        } catch (error) {
            setError("Erreur lors de l'ajout de l'action.");
        }
    };

    const portfolioData = {
        labels: portfolio.map(asset => asset.symbol),
        datasets: [
            {
                data: portfolio.map(asset => asset.quantity),
                backgroundColor: ['#FF6384', '#36A2EB', '#FFCE56', '#4BC0C0', '#9966FF'],
            }
        ]
    };

    const performanceData = {
        labels: ["Jan", "Fév", "Mar", "Avr", "Mai", "Juin", "Juil", "Août", "Sept", "Oct", "Nov", "Déc"],
        datasets: [
            {
                label: "Performance",
                data: [1000, 1200, 1300, 1250, 1400, 1600, 1550, 1700, 1900, 2000, 2100, 2300],
                fill: false,
                borderColor: "#36A2EB",
                tension: 0.4
            }
        ]
    };

    return (
        <>
            <Header />
            <div className="dashboard">
                <h2>📊 Mon Portefeuille</h2>
                {error && <p className="error">{error}</p>}

                <div className="charts">
                    <div className="chart-container">
                        <h3>Répartition des actifs</h3>
                        <Pie data={portfolioData} />
                    </div>
                    <div className="chart-container">
                        <h3>Performance du portefeuille</h3>
                        <Line data={performanceData} />
                    </div>
                </div>

                <h3>Mouvements Récents du Marché</h3>
                <div className="market-movements">
                    {marketData.length > 0 ? (
                        marketData.map((data, index) => (
                            <div key={index} className="market-item">
                                <span>{data.symbol} : {data.price} €</span>
                            </div>
                        ))
                    ) : (
                        <p>Aucune donnée disponible.</p>
                    )}
                </div>

                <div className="form-box">
                    <h3>➕ Ajouter un actif</h3>
                    <form onSubmit={handleAddAsset}>
                        <input type="text" placeholder="Symbole (ex: AAPL)" value={buySymbol} onChange={(e) => setBuySymbol(e.target.value)} required />
                        <input type="number" placeholder="Quantité" value={buyQuantity} onChange={(e) => setBuyQuantity(e.target.value)} required />
                        <button type="submit">Ajouter</button>
                    </form>
                </div>
            </div>
        </>
    );
};

export default Dashboard;
